ee:message.ee:set-payload:
%dw 2.0
output application/json
---
{
  items: (vars.createRequest.items default []) map ((item) -> {
    productId: item.productId,
    quantity: item.quantity
  })
}

%dw 2.0
output application/json
---
{
  orderId: payload.orderId,
  shippingAddress: vars.createRequest.shippingAddress default {
    line1: "123 Main Street",
    city: "San Francisco",
    state: "CA",
    postalCode: "94105",
    country: "US"
  }
}
